# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

from flask import Flask, request
from prometheus_client import Counter, generate_latest, CollectorRegistry
from prometheus_client.exposition import basic_auth_handler
from prometheus_client import make_wsgi_app
import os

app = Flask(__name__)
registry = CollectorRegistry()

# Create a dictionary to hold user-path metrics
user_path_metrics = {}

@app.route('/metrics')
def metrics():
    return generate_latest(registry)

@app.before_request
def track_requests():
    user_id = request.args.get('user_id', 'unknown')
    session_id = request.args.get('session_id', 'unknown')
    full_path = request.full_path

    metric_key = f'{user_id}_{full_path}'
    
    if metric_key not in user_path_metrics:
        user_path_metrics[metric_key] = Counter(
            f'http_requests_total_{user_id.replace("-", "_")}_{full_path.replace("/", "_").replace("-", "_")}',
            'Total HTTP requests for user-path combination',
            ['user_id', 'session_id', 'full_path'],
            registry=registry
        )
    
    user_path_metrics[metric_key].labels(user_id=user_id, session_id=session_id, full_path=full_path).inc()

@app.route('/')
def index():
    return "Welcome to the HTTP metrics tracking app!"

if __name__ == '__main__':
    app.wsgi_app = make_wsgi_app(registry)
    app.run(host='0.0.0.0', port=int(os.environ.get('PORT', 5000)))